namespace BgControls.Windows.Controls.DragDrop;/// <summary>/// 表示拖放查询事件的参数类./// </summary>public class DragDropQueryEventArgs : DragDropEventArgs{    /// <summary>    /// 表示空的事件参数实例.    /// </summary>    public static readonly DragDropQueryEventArgs EmptyArgs = new DragDropQueryEventArgs();    /// <summary>    /// Initializes a new instance of the <see cref="DragDropQueryEventArgs"/> class.    /// </summary>    /// <param name="routedEvent">路由事件标识.</param>    /// <param name="source">事件源对象.</param>    /// <param name="options">拖放选项配置.</param>    public DragDropQueryEventArgs(RoutedEvent routedEvent, object source, DragDropOptions options)        : base(routedEvent, source, options)    {        // 显式引用基类属性进行赋值.        this.Options = options;    }    /// <summary>    /// Initializes a new instance of the <see cref="DragDropQueryEventArgs"/> class.    /// </summary>    private DragDropQueryEventArgs()        : base(null!, null!, null!)    {        // 供静态只读字段 EmptyArgs 使用的内部私有构造函数.    }    /// <summary>    /// Gets or sets a value indicating whether 查询结果是否允许执行拖放操作.    /// </summary>    public bool? QueryResult { get; set; }    /// <summary>    /// 以类型安全的方式调用事件处理程序.    /// </summary>    /// <param name="genericHandler">通用的委托处理程序.</param>    /// <param name="genericTarget">事件触发的目标对象.</param>    protected override void InvokeEventHandler(Delegate genericHandler, object genericTarget)    {        // 将通用的 Delegate 转换为特定类型的 EventHandler 并执行.        (genericHandler as EventHandler<DragDropQueryEventArgs>)?.Invoke(genericTarget, this);    }}